// hooks/useColumnResize.ts
import { useState, useCallback, useRef } from 'react';

export function useColumnResize(initialWidths: Record<string, number>) {
  const [columnWidths, setColumnWidths] = useState(initialWidths);
  const resizing = useRef<{ key: string; startX: number; startWidth: number } | null>(null);

  const startResize = useCallback((key: string, e: React.MouseEvent) => {
    e.preventDefault();
    resizing.current = {
      key,
      startX: e.clientX,
      startWidth: columnWidths[key] || 150
    };

    const handleMouseMove = (e: MouseEvent) => {
      if (!resizing.current) return;
      const diff = e.clientX - resizing.current.startX;
      const newWidth = Math.max(50, resizing.current.startWidth + diff);
      setColumnWidths(prev => ({ ...prev, [resizing.current!.key]: newWidth }));
    };

    const handleMouseUp = () => {
      resizing.current = null;
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  }, [columnWidths]);

  return { columnWidths, startResize };
}
```

