// hooks/useTableKeyboardNav.ts
import { useState, useCallback, useEffect, useRef } from 'react';

export function useTableKeyboardNav(rowCount: number, colCount: number) {
  const [focusedCell, setFocusedCell] = useState<{ row: number; col: number } | null>(null);
  const tableRef = useRef<HTMLTableElement>(null);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (!focusedCell) return;

    const { row, col } = focusedCell;
    let newRow = row;
    let newCol = col;

    switch (e.key) {
      case 'ArrowUp':
        newRow = Math.max(0, row - 1);
        e.preventDefault();
        break;
      case 'ArrowDown':
        newRow = Math.min(rowCount - 1, row + 1);
        e.preventDefault();
        break;
      case 'ArrowLeft':
        newCol = Math.max(0, col - 1);
        e.preventDefault();
        break;
      case 'ArrowRight':
        newCol = Math.min(colCount - 1, col + 1);
        e.preventDefault();
        break;
      case 'Home':
        newCol = 0;
        if (e.ctrlKey) newRow = 0;
        e.preventDefault();
        break;
      case 'End':
        newCol = colCount - 1;
        if (e.ctrlKey) newRow = rowCount - 1;
        e.preventDefault();
        break;
      case 'Enter':
      case ' ':
        // Trigger row selection
        e.preventDefault();
        break;
      default:
        return;
    }

    setFocusedCell({ row: newRow, col: newCol });
  }, [focusedCell, rowCount, colCount]);

  useEffect(() => {
    const table = tableRef.current;
    if (!table) return;

    table.addEventListener('keydown', handleKeyDown as any);
    return () => table.removeEventListener('keydown', handleKeyDown as any);
  }, [handleKeyDown]);

  return { focusedCell, setFocusedCell, tableRef };
}
```

