export function DataTable<T extends { id: string | number }>({
  // ... existing props
  selectable = false,
  selectedIds = new Set(),
  onSelectionChange
}: DataTableProps<T>) {

  const allSelected = paginatedData.length > 0 && 
    paginatedData.every(row => selectedIds.has(row.id));

  const someSelected = paginatedData.some(row => selectedIds.has(row.id)) && !allSelected;

  const handleSelectAll = () => {
    if (allSelected) {
      // Deselect all on current page
      const newSelection = new Set(selectedIds);
      paginatedData.forEach(row => newSelection.delete(row.id));
      onSelectionChange?.(newSelection);
    } else {
      // Select all on current page
      const newSelection = new Set(selectedIds);
      paginatedData.forEach(row => newSelection.add(row.id));
      onSelectionChange?.(newSelection);
    }
  };

  const handleSelectRow = (id: string | number) => {
    const newSelection = new Set(selectedIds);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    onSelectionChange?.(newSelection);
  };

  return (
    <table className="data-table" role="grid">
      <thead>
        <tr>
          {selectable && (
            <th className="checkbox-cell">
              <input
                type="checkbox"
                checked={allSelected}
                ref={el => { if (el) el.indeterminate = someSelected; }}
                onChange={handleSelectAll}
                aria-label="Select all rows"
