import React, { useState, useRef, useEffect } from 'react';

interface ColumnToggleProps<T> {
  columns: Column<T>[];
  visibleColumns: Set<keyof T>;
  onToggle: (key: keyof T) => void;
}

export function ColumnToggle<T>({ 
  columns, 
  visibleColumns, 
  onToggle 
}: ColumnToggleProps<T>) {
  const [isOpen, setIsOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  // Close on outside click
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="column-toggle" ref={menuRef}>
      <button 
        className="column-toggle-btn"
        onClick={() => setIsOpen(!isOpen)}
        aria-expanded={isOpen}
        aria-haspopup="menu"
      >
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <path d="M12 3v18M3 12h18" />
        </svg>
        Columns
      </button>

      {isOpen && (
        <div className="column-toggle-menu" role="menu">
          {columns.map(col => (
            <label key={String(col.key)} className="column-toggle-item">
              <input
                type="checkbox"
                checked={visibleColumns.has(col.key)}
                onChange={() => onToggle(col.key)}
              />
              {col.header}
            </label>
          ))}
        </div>
      )}
    </div>
  );
}
