// internal/service/task_service.go
package service

import (
    "context"
    "errors"
    "myapp/internal/domain"
)

var (
    ErrTaskNotFound = errors.New("task not found")
    ErrForbidden    = errors.New("forbidden")
)

type TaskService struct {
    repo        domain.TaskRepository
    projectRepo domain.ProjectRepository
    activityLog domain.ActivityLogger
}

func NewTaskService(
    repo domain.TaskRepository,
    projectRepo domain.ProjectRepository,
    activityLog domain.ActivityLogger,
) *TaskService {
    return &TaskService{
        repo:        repo,
        projectRepo: projectRepo,
        activityLog: activityLog,
    }
}

func (s *TaskService) Create(ctx context.Context, userID uuid.UUID, input CreateTaskInput) (*domain.Task, error) {
    // Verify user has access to project
    if err := s.checkProjectAccess(ctx, userID, input.ProjectID); err != nil {
        return nil, err
    }

    task := &domain.Task{
        ID:          uuid.New(),
        ProjectID:   input.ProjectID,
        Title:       input.Title,
        Description: input.Description,
        Status:      domain.StatusTodo,
        Priority:    input.Priority,
        ReporterID:  userID,
        AssigneeID:  input.AssigneeID,
        DueDate:     input.DueDate,
        Tags:        input.Tags,
        CreatedAt:   time.Now(),
        UpdatedAt:   time.Now(),
    }

    if err := s.repo.Create(ctx, task); err != nil {
        return nil, fmt.Errorf("create task: %w", err)
    }

    // Log activity
    s.activityLog.Log(ctx, domain.ActivityEntry{
        EntityType: "task",
        EntityID:   task.ID,
        Action:     "created",
        ActorID:    userID,
    })

    return task, nil
}

func (s *TaskService) checkProjectAccess(ctx context.Context, userID, projectID uuid.UUID) error {
    project, err := s.projectRepo.GetByID(ctx, projectID)
    if err != nil {
        return err
    }

    // Check if user is owner or member
    if project.OwnerID == userID {
        return nil
    }

    isMember, err := s.projectRepo.IsMember(ctx, projectID, userID)
    if err != nil {
        return err
    }

    if !isMember {
        return ErrForbidden
    }

    return nil
}
