// internal/handler/task_handler.go
package handler

import (
    "encoding/json"
    "net/http"

    "github.com/go-chi/chi/v5"
    "github.com/google/uuid"
)

type TaskHandler struct {
    service *service.TaskService
}

func NewTaskHandler(service *service.TaskService) *TaskHandler {
    return &TaskHandler{service: service}
}

func (h *TaskHandler) Routes() chi.Router {
    r := chi.NewRouter()

    r.Get("/", h.List)
    r.Post("/", h.Create)
    r.Route("/{taskID}", func(r chi.Router) {
        r.Get("/", h.GetByID)
        r.Patch("/", h.Update)
        r.Delete("/", h.Delete)
    })

    return r
}

func (h *TaskHandler) Create(w http.ResponseWriter, r *http.Request) {
    var input service.CreateTaskInput
    if err := json.NewDecoder(r.Body).Decode(&input); err != nil {
        respondError(w, http.StatusBadRequest, "invalid request body")
        return
    }

    // Validate input
    if err := input.Validate(); err != nil {
        respondError(w, http.StatusUnprocessableEntity, err.Error())
        return
    }

    // Get user from context (set by auth middleware)
    userID := getUserID(r.Context())

    task, err := h.service.Create(r.Context(), userID, input)
    if err != nil {
        switch {
        case errors.Is(err, service.ErrForbidden):
            respondError(w, http.StatusForbidden, "access denied")
        default:
            respondError(w, http.StatusInternalServerError, "internal error")
        }
        return
    }

    respondJSON(w, http.StatusCreated, task)
}

func (h *TaskHandler) List(w http.ResponseWriter, r *http.Request) {
    filter := domain.TaskFilter{
        ProjectID:  parseUUIDQuery(r, "project_id"),
        AssigneeID: parseUUIDQuery(r, "assignee_id"),
        Status:     parseStatusQuery(r, "status"),
        Priority:   parsePriorityQuery(r, "priority"),
    }

    page := parseIntQuery(r, "page", 1)
    limit := parseIntQuery(r, "limit", 20)
    if limit > 100 {
        limit = 100
    }

    tasks, total, err := h.service.List(r.Context(), filter, page, limit)
    if err != nil {
        respondError(w, http.StatusInternalServerError, "internal error")
        return
    }

    respondJSON(w, http.StatusOK, map[string]interface{}{
        "data": tasks,
        "pagination": map[string]int{
            "page":        page,
            "limit":       limit,
            "total":       total,
            "total_pages": (total + limit - 1) / limit,
        },
    })
}

func (h *TaskHandler) GetByID(w http.ResponseWriter, r *http.Request) {
    taskID, err := uuid.Parse(chi.URLParam(r, "taskID"))
    if err != nil {
        respondError(w, http.StatusBadRequest, "invalid task ID")
        return
    }

    task, err := h.service.GetByID(r.Context(), taskID)
    if err != nil {
