// cmd/api/main.go
package main

import (
    "context"
    "log"
    "net/http"
    "os"
    "os/signal"
    "syscall"
    "time"

    "github.com/go-chi/chi/v5"
    "github.com/go-chi/chi/v5/middleware"
    "github.com/jackc/pgx/v5/pgxpool"

    "myapp/internal/handler"
    "myapp/internal/repository"
    "myapp/internal/service"
)

func main() {
    // Load config
    cfg := loadConfig()

    // Database connection pool
    dbPool, err := pgxpool.New(context.Background(), cfg.DatabaseURL)
    if err != nil {
        log.Fatalf("Unable to connect to database: %v", err)
    }
    defer dbPool.Close()

    // Initialize repositories
    userRepo := repository.NewUserRepository(dbPool)
    projectRepo := repository.NewProjectRepository(dbPool)
    taskRepo := repository.NewTaskRepository(dbPool)
    activityLog := repository.NewActivityLogger(dbPool)

    // Initialize services
    authService := service.NewAuthService(userRepo, cfg.JWTSecret)
    projectService := service.NewProjectService(projectRepo, activityLog)
    taskService := service.NewTaskService(taskRepo, projectRepo, activityLog)

    // Initialize handlers
    authHandler := handler.NewAuthHandler(authService)
    projectHandler := handler.NewProjectHandler(projectService)
    taskHandler := handler.NewTaskHandler(taskService)

    // Setup router
    r := chi.NewRouter()

    // Middleware
    r.Use(middleware.Logger)
    r.Use(middleware.Recoverer)
    r.Use(middleware.Timeout(30 * time.Second))
    r.Use(corsMiddleware())

    // Health check
    r.Get("/health", func(w http.ResponseWriter, r *http.Request) {
        w.Write([]byte("OK"))
    })

    // API routes
    r.Route("/api/v1", func(r chi.Router) {
        // Public routes
        r.Mount("/auth", authHandler.PublicRoutes())

        // Protected routes
        r.Group(func(r chi.Router) {
            r.Use(authMiddleware(authService))

            r.Mount("/users", handler.NewUserHandler(userRepo).Routes())
            r.Mount("/projects", projectHandler.Routes())
            r.Mount("/tasks", taskHandler.Routes())
        })
    })

    // Create server
    srv := &http.Server{
        Addr:         ":" + cfg.Port,
        Handler:      r,
        ReadTimeout:  15 * time.Second,
        WriteTimeout: 15 * time.Second,
        IdleTimeout:  60 * time.Second,
    }

    // Graceful shutdown
    go func() {
        log.Printf("Server starting on port %s", cfg.Port)
        if err := srv.ListenAndServe(); err != http.ErrServerClosed {
            log.Fatalf("Server error: %v", err)
        }
    }()

    // Wait for interrupt signal
    quit := make(chan os.Signal, 1)
    signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
    <-quit

    log.Println("Shutting down server...")

    ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
    defer cancel()

    if err := srv.Shutdown(ctx); err != nil {
        log.Fatalf("Server forced to shutdown: %v", err)
    }

    log.Println("Server exited gracefully")
}
