pub async fn create_pool(url: &str) -> Result<Pool, PoolError> {
    let manager = Manager::new(url);

    for attempt in 1..=5 {
        match Pool::builder(manager.clone()).build() {
            Ok(pool) => {
                tracing::info!("Database connected on attempt {}", attempt);
                return Ok(pool);
            }
            Err(e) => {
                tracing::warn!("DB connection attempt {} failed: {:?}", attempt, e);
                if attempt < 5 {
                    tokio::time::sleep(Duration::from_secs(2_u64.pow(attempt))).await;
