use anyhow::{Context, Result};
use clap::Parser;
use csv::ReaderBuilder;
use serde_json::{json, Map, Value};
use std::collections::HashMap;
use std::fs::File;
use std::io::{self, BufWriter, Write};
use std::path::PathBuf;

#[derive(Parser, Debug)]
#[command(name = "csvtool")]
#[command(about = "Convert CSV to JSON with filtering and column selection")]
struct Cli {
    /// Input CSV file (use - for stdin)
    #[arg(short, long)]
    input: PathBuf,

    /// Output file (defaults to stdout)
    #[arg(short, long)]
    output: Option<PathBuf>,

    /// Select specific columns (comma-separated)
    #[arg(short, long, value_delimiter = ',')]
    select: Option<Vec<String>>,

    /// Filter by column value (format: column=value)
    #[arg(short, long, value_parser = parse_filter)]
    filter: Option<Vec<(String, String)>>,

    /// Output as JSON array (default) or newline-delimited JSON
    #[arg(long)]
    ndjson: bool,

    /// Pretty print JSON output
    #[arg(long)]
    pretty: bool,

    /// CSV has no header row
    #[arg(long)]
    no_header: bool,

    /// Field delimiter (default: comma)
    #[arg(short, long, default_value = ",")]
    delimiter: char,
}

fn parse_filter(s: &str) -> Result<(String, String), String> {
    let parts: Vec<&str> = s.splitn(2, '=').collect();
    if parts.len() != 2 {
        return Err(format!("Filter must be in format 'column=value', got: {}", s));
    }
    Ok((parts[0].to_string(), parts[1].to_string()))
}

fn main() -> Result<()> {
    let cli = Cli::parse();

    // Open input
    let reader: Box<dyn io::Read> = if cli.input.to_string_lossy() == "-" {
        Box::new(io::stdin())
    } else {
        Box::new(File::open(&cli.input)
            .with_context(|| format!("Failed to open input file: {:?}", cli.input))?)
    };

    // Build CSV reader
    let mut csv_reader = ReaderBuilder::new()
        .has_headers(!cli.no_header)
        .delimiter(cli.delimiter as u8)
        .from_reader(reader);

    // Get headers
    let headers: Vec<String> = if cli.no_header {
        // Generate column names: col0, col1, etc.
        let first_record = csv_reader.records().next()
            .ok_or_else(|| anyhow::anyhow!("Empty CSV file"))??;
        (0..first_record.len()).map(|i| format!("col{}", i)).collect()
    } else {
        csv_reader.headers()?
            .iter()
            .map(|s| s.to_string())
            .collect()
    };

    // Validate selected columns exist
    if let Some(ref select) = cli.select {
        for col in select {
            if !headers.contains(col) {
                anyhow::bail!("Column '{}' not found. Available: {:?}", col, headers);
            }
        }
    }

    // Validate filter columns exist
    if let Some(ref filters) = cli.filter {
        for (col, _) in filters {
            if !headers.contains(col) {
                anyhow::bail!("Filter column '{}' not found. Available: {:?}", col, headers);
            }
        }
    }

    // Process records
    let mut records: Vec<Value> = Vec::new();

    for result in csv_reader.records() {
        let record = result?;

        // Build row map
        let mut row: Map<String, Value> = Map::new();
        for (i, value) in record.iter().enumerate() {
            if i < headers.len() {
                row.insert(headers[i].clone(), json!(value));
            }
        }

        // Apply filters
        if let Some(ref filters) = cli.filter {
            let mut matches = true;
            for (col, expected) in filters {
                if let Some(Value::String(actual)) = row.get(col) {
                    if actual != expected {
                        matches = false;
                        break;
                    }
                } else {
                    matches = false;
                    break;
                }
            }
            if !matches {
                continue;
            }
        }

        // Select columns
        let output_row: Value = if let Some(ref select) = cli.select {
            let mut selected: Map<String, Value> = Map::new();
            for col in select {
                if let Some(v) = row.get(col) {
                    selected.insert(col.clone(), v.clone());
                }
            }
            Value::Object(selected)
        } else {
            Value::Object(row)
        };

        records.push(output_row);
    }

    // Write output
    let mut writer: Box<dyn Write> = match cli.output {
        Some(path) => Box::new(BufWriter::new(
            File::create(&path)
                .with_context(|| format!("Failed to create output file: {:?}", path))?
        )),
        None => Box::new(io::stdout()),
    };

    if cli.ndjson {
        for record in &records {
            let line = serde_json::to_string(record)?;
            writeln!(writer, "{}", line)?;
        }
    } else if cli.pretty {
        let json = serde_json::to_string_pretty(&records)?;
        writeln!(writer, "{}", json)?;
    } else {
        let json = serde_json::to_string(&records)?;
        writeln!(writer, "{}", json)?;
    }

    Ok(())
}
