#[test]
fn test_basic_conversion() {
    let dir = tempdir().unwrap();
    let input = dir.path().join("test.csv");
    let output = dir.path().join("output.json");

    fs::write(&input, "name,age,city\nAlice,30,NYC\nBob,25,LA").unwrap();

    let status = Command::new("cargo")
        .args(["run", "--", "-i", input.to_str().unwrap(), "-o", output.to_str().unwrap()])
        .status()
        .unwrap();

    assert!(status.success());

    let result = fs::read_to_string(&output).unwrap();
    let parsed: Vec<serde_json::Value> = serde_json::from_str(&result).unwrap();

    assert_eq!(parsed.len(), 2);
    assert_eq!(parsed[0]["name"], "Alice");
    assert_eq!(parsed[1]["city"], "LA");
}

#[test]
fn test_column_selection() {
    let dir = tempdir().unwrap();
    let input = dir.path().join("test.csv");
    let output = dir.path().join("output.json");

    fs::write(&input, "id,name,email,role\n1,Alice,a@x.com,admin\n2,Bob,b@x.com,user").unwrap();

    let status = Command::new("cargo")
        .args(["run", "--", 
               "-i", input.to_str().unwrap(), 
               "-o", output.to_str().unwrap(),
               "-s", "name,role"])
        .status()
        .unwrap();

    assert!(status.success());

    let result = fs::read_to_string(&output).unwrap();
    let parsed: Vec<serde_json::Value> = serde_json::from_str(&result).unwrap();

    // Should only have name and role columns
    assert!(parsed[0].get("id").is_none());
    assert_eq!(parsed[0]["name"], "Alice");
    assert_eq!(parsed[0]["role"], "admin");
}

#[test]
fn test_filtering() {
    let dir = tempdir().unwrap();
    let input = dir.path().join("test.csv");
    let output = dir.path().join("output.json");

    fs::write(&input, "name,role\nAlice,admin\nBob,user\nCarol,admin").unwrap();

    let status = Command::new("cargo")
