// Add to main.rs

#[derive(Debug, Clone)]
enum FilterOp {
    Eq,      // =
    Ne,      // !=
    Gt,      // >
    Gte,     // >=
    Lt,      // <
    Lte,     // <=
    Contains, // ~
}

#[derive(Debug, Clone)]
struct Filter {
    column: String,
    op: FilterOp,
    value: String,
}

fn parse_filter(s: &str) -> Result<Filter, String> {
    // Try operators in order of length (longest first)
    let operators = [
        ("!=", FilterOp::Ne),
        (">=", FilterOp::Gte),
        ("<=", FilterOp::Lte),
        ("=", FilterOp::Eq),
        (">", FilterOp::Gt),
        ("<", FilterOp::Lt),
        ("~", FilterOp::Contains),
    ];

    for (op_str, op) in operators {
        if let Some(pos) = s.find(op_str) {
            let column = s[..pos].trim().to_string();
            let value = s[pos + op_str.len()..].trim().to_string();
            if column.is_empty() {
                return Err(format!("Missing column name in filter: {}", s));
            }
            return Ok(Filter { column, op, value });
        }
    }

    Err(format!("Invalid filter format: {}. Use column=value, column>value, etc.", s))
}

fn apply_filter(row: &Map<String, Value>, filter: &Filter) -> bool {
    let Some(Value::String(actual)) = row.get(&filter.column) else {
        return false;
    };

    match filter.op {
        FilterOp::Eq => actual == &filter.value,
        FilterOp::Ne => actual != &filter.value,
        FilterOp::Contains => actual.contains(&filter.value),
        FilterOp::Gt | FilterOp::Gte | FilterOp::Lt | FilterOp::Lte => {
            // Try numeric comparison
            if let (Ok(a), Ok(b)) = (actual.parse::<f64>(), filter.value.parse::<f64>()) {
                match filter.op {
                    FilterOp::Gt => a > b,
                    FilterOp::Gte => a >= b,
                    FilterOp::Lt => a < b,
                    FilterOp::Lte => a <= b,
                    _ => unreachable!(),
                }
            } else {
                // Fall back to string comparison
                match filter.op {
                    FilterOp::Gt => actual.as_str() > filter.value.as_str(),
                    FilterOp::Gte => actual.as_str() >= filter.value.as_str(),
                    FilterOp::Lt => actual.as_str() < filter.value.as_str(),
                    FilterOp::Lte => actual.as_str() <= filter.value.as_str(),
                    _ => unreachable!(),
                }
            }
        }
    }
}
