#[arg(long, value_enum, default_value = "json")]
format: OutputFormat,

#[derive(Clone, Copy, ValueEnum, Debug)]
enum OutputFormat {
    Json,
    Csv,
    Tsv,
}

// Update output section
match cli.format {
    OutputFormat::Json => {
        if cli.ndjson {
            for record in &records {
                writeln!(writer, "{}", serde_json::to_string(record)?)?;
            }
        } else if cli.pretty {
            writeln!(writer, "{}", serde_json::to_string_pretty(&records)?)?;
        } else {
            writeln!(writer, "{}", serde_json::to_string(&records)?)?;
        }
    }
    OutputFormat::Csv | OutputFormat::Tsv => {
        let delim = if matches!(cli.format, OutputFormat::Tsv) { b'\t' } else { b',' };
        let mut csv_writer = csv::WriterBuilder::new()
            .delimiter(delim)
            .from_writer(writer);

        // Write header
        let columns: Vec<&str> = if let Some(ref select) = cli.select {
            select.iter().map(|s| s.as_str()).collect()
        } else {
            headers.iter().map(|s| s.as_str()).collect()
        };
        csv_writer.write_record(&columns)?;

        // Write records
        for record in &records {
            let row: Vec<String> = columns.iter()
                .map(|col| {
                    record.get(*col)
                        .and_then(|v| v.as_str())
                        .unwrap_or("")
                        .to_string()
                })
                .collect();
            csv_writer.write_record(&row)?;
        }
        csv_writer.flush()?;
    }
}
